var UserConnection = Get<UserConnection>("UserConnection");
Guid crmGroupId = Get<Guid>("CRMGroupId");
string hierarchy = Get<string>("Hierarcy");

var log = new CustomLog(UserConnection, $"Auto_Update_GroupNo_{crmGroupId}_{hierarchy}");

bool isSuccess = false;
int i = 0;
int delay = 1000 * 45; // 1 minutes --> 45s
bool isSaveCustomerId = false;
bool isSaveAccountId = false;
bool isSaveGroupNo = false;
string customerId = string.Empty;

var crmService = new CRMService(UserConnection);

while (!isSuccess) {
    if(i > 5) {
        break;
    }

    Thread.Sleep(delay);
    
    log.AddMessage("Auto Update start...", true);
    log.AddMessage($"Attempt {i+1}", true);
    
    try {
    	if(!isSaveCustomerId) {
    		log.AddMessage("Request Get Customer", true);
    		
            var customers = crmService.GetCustomersByCRMGroup(crmGroupId).GetAwaiter().GetResult();
            if(customers == null) {
                throw new Exception("Get Customer not found");
            }

            var customer = customers
                .Where(item => item.corporationInfo.hierarchy == hierarchy)
                .FirstOrDefault();
            customerId = customer.customerId;
            string customerCode = customer.customerCode;
            string corpNumber = customer.corporationInfo.corpNumber;

            new Update(UserConnection, "DgCRMGroup")
                .Set(hierarchy == "2" ? "DgSubParentCustomerId" : "DgParentCustomerId", Column.Parameter(customerId))
                .Set(hierarchy == "2" ? "DgSubParentCustomerCode" : "DgCustomerCode", Column.Parameter(customerCode))
                .Set(hierarchy == "2" ? "DgSubParentCorporateNumber" : "DgCorporateNumber", Column.Parameter(corpNumber))
                .Where("Id").IsEqual(Column.Parameter(crmGroupId))
            .Execute();
            isSaveCustomerId = true;
            
            log.AddMessage("Customer found and update customerId, customerCode, corpNumber", true);
        }
    } catch(Exception e) {
    	log.AddMessage($"Response Get Customer: \n{e.Message}", true);
    }
    
	try {
		if(!isSaveAccountId && !string.IsNullOrEmpty(customerId)) {
			log.AddMessage("Request Get Account", true);
			
            var accounts = crmService.GetAccountsByCustomerId(customerId).GetAwaiter().GetResult();
            if(accounts == null) {
                throw new Exception("Get Account not found");
            }

            var account = accounts.FirstOrDefault();
            string accountId = account.accountId;
            string accountCode = account.accountCode;
            string billcycleType = account.billcycleType;
            string paymentId = account.paymentModeInfo.paymentId;

            var updateAccountInfo = new Update(UserConnection, "DgCRMGroup")
                .Set(hierarchy == "2" ? "DgSubParentAccountId" : "DgAccountId", Column.Parameter(accountId))
                .Set(hierarchy == "2" ? "DgSubParentAccountCode" : "DgAccountCode", Column.Parameter(accountCode))
                .Set(hierarchy == "2" ? "DgSubParentPaymentId" : "DgPaymentId", Column.Parameter(paymentId));
                
            if(hierarchy == "2") {
            	var select = new Select(UserConnection)
				    .Column("Id").As("Id")
				.From("DgSubmission")
				.Where("DgCRMGroupId").IsEqual(Column.Parameter(crmGroupId))
				.And("DgSubmissionTypeId").IsEqual(Column.Parameter(Guid.Parse("1cf9b17c-9085-4646-b499-53cdf15156b2"))) as Select;
				
				using (DBExecutor dbExecutor = UserConnection.EnsureDBConnection()) 
				{
				    using (IDataReader dataReader = select.ExecuteReader(dbExecutor))
				    {
				        while (dataReader.Read()) 
				        {
				            var submissionId = dataReader.GetColumnValue("Id") != null ? 
				                Guid.Parse(dataReader.GetColumnValue("Id").ToString()) : Guid.Empty;
				                
				            new Update(UserConnection, "DgLineDetail")
				                .Set("DgDNOAccNo", Column.Parameter(accountCode))
				                .Where("DgSubmissionId").IsEqual(Column.Parameter(submissionId))
				            .Execute();
				        }
				    }
				}
            }

            if(hierarchy == "1") {
                updateAccountInfo
                    .Set("DgBillingCycle", Column.Parameter(billcycleType));
            }
            
            updateAccountInfo
                .Where("Id").IsEqual(Column.Parameter(crmGroupId))
                .Execute();
            isSaveAccountId = true;
            
            log.AddMessage("Account found and update accountId, accountCode, paymentId, billcycleType", true);
        }
	} catch(Exception e) {
		log.AddMessage($"Response Get Account: \n{e.Message}", true);
	}

	try {
		if(!isSaveGroupNo && !string.IsNullOrEmpty(customerId)) {
            var queryVPNs = crmService.QueryVPNGroupSubscriberByCustomerId(customerId).GetAwaiter().GetResult();
            if(queryVPNs == null) {
                throw new Exception("Query VPN Group Subscriber not found");
            }

            var queryVPN = queryVPNs.FirstOrDefault();
            string groupNumber = queryVPN.groupNumber ?? string.Empty;
            string groupId = queryVPN.groupId ?? string.Empty;
            if(string.IsNullOrEmpty(groupNumber) || string.IsNullOrEmpty(groupId)) {
                throw new Exception("Group Id is empty");
            }

            new Update(UserConnection, "DgCRMGroup")
                .Set(hierarchy == "2" ? "DgGroupSubParentNo" : "DgGroupNo", Column.Parameter(groupNumber))
                .Set(hierarchy == "2" ? "DgSubParentGroupID" : "DgGroupID", Column.Parameter(groupId))
                .Where("Id").IsEqual(Column.Parameter(crmGroupId))
            .Execute();

            isSuccess = true;
            isSaveGroupNo = true;
            
            log.AddMessage("Query VPN Group Subscibers found and update groupNo, groupId", true);
        }
	} catch(Exception e) {
		log.AddMessage($"Response Query VPN Group Subscibers: \n{e.Message}", true);
	}
	
	i++;
}

log.SaveToFile();

return true;
